#include<bits/stdc++.h>
#define endl "\n"
using namespace std;
long long n, a[1004], b[200000008];

int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
		if(i!=1) b[abs(a[i]-a[i-1])]++;
	}
	for (int i = 1; i <= n - 1; i++) {
		if (b[i] == 0) {

			cout << "Not jolly" << endl;
			return 0;
		}
	}
	cout << "Jolly" << endl;
	return 0;
}
